from skimage import io, img_as_floatfrom matplotlib import pyplot as pltimport cv2import bm3dnoisy_img = img_as_float(io.imread('../data/BSE_25sigma_noisy.jpg', as_gray=True))BM3D_denoised = bm3d.bm3d(noisy_img, sigma_psd = 0.2, stage_arg = bm3d.BM3DStages.ALL_STAGES)plt.figure()plt.subplot(1,2,1)plt.imshow(noisy_img, cmap  = "gray")plt.title("Original")plt.subplot(1,2,2)plt.imshow(BM3D_denoised, cmap = "gray")plt.title("BM3D denoised")'''sigma_psdRepresents the estimated noise level in the image.Small → weaker denoisingLarge → stronger smoothingstage_argbm3d.BM3DStages.ALL_STAGESUses the complete BM3D pipeline:Hard-thresholding stageWiener filtering stage'''